//import logo from './logo.svg';
import './App.css';
import React from 'react';
import "./styles.css";
import Navbar from "./components/navbar";
import Homepage_image from "./components/assets/Homepage_image.png";
import * as BannerImages from './components/assets'; // Import all images from the index file

export default function App() {
  return (
    <div className="App">
      <Navbar/>
      <div style={{ display: 'flex', alignItems: 'center', marginRight: '200px', marginTop: '50px' }}>
        <div style={{ flex: '1' }}>
          <h1 style={{ fontSize: "4.5rem",marginBottom: "0.2rem",fontFamily: "Montserrat, sans-serif", color: "orange"}}>QuickLocalFix </h1>
          <h2 style={{  marginTop: "0.5rem",fontSize: "3.5rem",marginBottom: "0.5rem"}}>Repair Services</h2>
          <h5> RESTORING EXCELLENCE,REPAIRING WITH PRECISION</h5>
        </div>
        <img src = {Homepage_image} alt="Homepage" style={{ width: '300px', height: 'auto', maxWidth: '50%', maxHeight: '40vh' }} />    
      </div>

      {/* Banner Section */}
      <div className="banner">
        <div style={{ display:'flex', justifyContent: 'center', marginTop: '25px' }}>
        <div className="box"></div>
          {Object.values(BannerImages).map((image, index) => (
          <img key={index} src={image} alt={`${index + 1}`} style={{ width: '288px', height: 'auto', margin: '0 0px' }}/>
          ))}
        </div>
      </div>
    </div>
  );
}



